<?php
namespace App\Repositories;
use App\Models\Campaign; use Illuminate\Contracts\Pagination\LengthAwarePaginator;
class CampaignRepository { public function publicList(array $filters=[]): LengthAwarePaginator { return Campaign::query()->with(['category','fundraiser'])->where('status','active')->when($filters['q'] ?? null, fn($q,$s)=>$q->where('title','like',"%{$s}%"))->when($filters['category'] ?? null, fn($q,$c)=>$q->whereHas('category', fn($cat)=>$cat->where('slug',$c)))->latest()->paginate(9)->withQueryString(); } public function dashboardList(?int $fundraiserId=null): LengthAwarePaginator { return Campaign::query()->with('category')->when($fundraiserId, fn($q)=>$q->where('fundraiser_id',$fundraiserId))->latest()->paginate(10); } public function findBySlug(string $slug): Campaign { return Campaign::with(['category','fundraiser','updates','donations'=>fn($q)=>$q->where('status','verified')->latest()->limit(10),'transparencyReports'])->where('slug',$slug)->firstOrFail(); } }
